import{_ as e,o as d,c as o,a2 as a}from"./chunks/framework.b3aQeZRM.js";const u=JSON.parse('{"title":"Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"configuration.md","filePath":"configuration.md"}'),r={name:"configuration.md"};function i(c,t,n,l,s,p){return d(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h1><p>Relay reads environment variables from process env (and commonly from <code>.env</code>).</p><h2 id="core-variables" tabindex="-1">Core Variables <a class="header-anchor" href="#core-variables" aria-label="Permalink to &quot;Core Variables&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Notes</th></tr></thead><tbody><tr><td><code>HOST</code></td><td><code>127.0.0.1</code></td><td>Bind address</td></tr><tr><td><code>PORT</code></td><td><code>1234</code></td><td>Bind port</td></tr><tr><td><code>UPSTREAM_BASE_URL</code></td><td><code>http://127.0.0.1:8080/v1</code></td><td>Upstream API root</td></tr><tr><td><code>UPSTREAM_CTX_SIZE</code></td><td><em>(empty)</em></td><td>Running upstream context size (for example llama.cpp <code>--ctx-size</code>) exposed for clients</td></tr><tr><td><code>DEFAULT_MODEL</code></td><td><em>(empty)</em></td><td>Fallback model</td></tr><tr><td><code>REQUEST_TIMEOUT_SECONDS</code></td><td><code>600</code></td><td>Upstream timeout</td></tr><tr><td><code>MAX_REQUEST_BODY_BYTES</code></td><td><code>1048576</code></td><td>Body size limit</td></tr><tr><td><code>API_KEY</code></td><td><em>(empty)</em></td><td>If set, require auth key</td></tr></tbody></table><h2 id="startup-and-logging" tabindex="-1">Startup And Logging <a class="header-anchor" href="#startup-and-logging" aria-label="Permalink to &quot;Startup And Logging&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Notes</th></tr></thead><tbody><tr><td><code>RELAY_PROBE_ON_STARTUP</code></td><td><code>true</code></td><td>Probe upstream during startup</td></tr><tr><td><code>RELAY_STRICT_STARTUP</code></td><td><code>false</code></td><td>Exit if probe fails</td></tr><tr><td><code>RELAY_OBSERVABILITY_ENABLED</code></td><td><code>true</code></td><td>Enable <code>/relay/*</code> endpoints</td></tr><tr><td><code>RELAY_LOG_PROMPTS</code></td><td><code>false</code></td><td>Log prompt bodies</td></tr><tr><td><code>LOG_LEVEL</code></td><td><code>info</code></td><td>Log level</td></tr></tbody></table><h2 id="compatibility-tuning" tabindex="-1">Compatibility Tuning <a class="header-anchor" href="#compatibility-tuning" aria-label="Permalink to &quot;Compatibility Tuning&quot;">​</a></h2><p>Relay supports multiple model profiles and field handling policies for better behavior with local providers.</p><ul><li><code>RELAY_MODEL_PROFILE</code> controls defaults for known model families.</li><li><code>RELAY_FIELD_POLICY</code> controls how unknown/hosted-only fields are handled.</li></ul><p>Use strict modes when you want predictable failures; use permissive modes when maximizing client compatibility.</p>',10)])])}const h=e(r,[["render",i]]);export{u as __pageData,h as default};
